code = """import pandas as pd
import re

businesses_credit_cards = locals()['var_function-call-16316061533982366013']
df_businesses = pd.DataFrame(businesses_credit_cards)

def extract_categories(description):
    match = re.search(r'services in (.+?)(?:$|\.)', description)
    if match:
        categories_str = match.group(1).strip()
        categories_str = categories_str.replace(" and ", ", ").replace(", and ", ", ")
        categories = [cat.strip() for cat in categories_str.split(',') if cat.strip()]
        return categories
    return []

df_businesses['categories'] = df_businesses['description'].apply(extract_categories)
exploded_categories = df_businesses.explode('categories')

category_counts = exploded_categories['categories'].value_counts().reset_index()
category_counts.columns = ['category', 'business_count']

most_common_category_info = category_counts.loc[category_counts['business_count'].idxmax()]

most_common_category = most_common_category_info['category']

business_ids_in_most_common_category = exploded_categories[exploded_categories['categories'] == most_common_category]['business_id'].tolist()

# Convert business_id prefix for joining with review table
business_refs_for_query = [bid.replace("businessid_", "businessref_") for bid in business_ids_in_most_common_category]

# Store for next step
print("__RESULT__:")
print(pd.Series({
    "most_common_category": most_common_category,
    "business_refs_for_query": business_refs_for_query
}).to_json())"""

